/**
 * shell-init.ts — Shell Integration Command
 *
 * Outputs shell hooks for bash/zsh that track terminal session lifecycle.
 * Users add `eval "$(shiten shell-init)"` to their .bashrc/.zshrc.
 *
 * PRINCIPLE: The system should know when a developer starts/stops working.
 */

import { Command } from "commander";

// ── Shell Script ─────────────────────────────────────────────────────────────

const SHELL_SCRIPT = [
  "# ── Shiten Shell Integration ──────────────────────────────────────────────────",
  "# Auto-generated by 'shiten shell-init'. Do not edit manually.",
  '# Add eval "$(shiten shell-init)" to your .bashrc/.zshrc.',
  "",
  '_shiten_session_id=""',
  '_shiten_session_start=""',
  "",
  "_shiten_hook_preexec() {",
  '  _shiten_session_start=$(date +%s)',
  "  command -v shiten >/dev/null 2>&1 && shiten feedback --outcome session-start 2>/dev/null &",
  "  # Show active reminders at session start",
  "  command -v shiten >/dev/null 2>&1 && shiten reminders 2>/dev/null &",
  "  # Send desktop notification for high priority reminders",
  '  if command -v notify-send >/dev/null 2>&1; then',
  '    _shiten_high_reminders=$(shiten reminders --json 2>/dev/null | grep -o \'"priority":"high"\' | wc -l)',
  '    if [ "$_shiten_high_reminders" -gt 0 ]; then',
  '      notify-send "Shiten" "🔴 $_shiten_high_reminders HIGH priority reminder(s) require attention" --urgency=critical 2>/dev/null',
  "    fi",
  "  fi",
  "}",
  "",
  "_shiten_hook_precmd() {",
  '  if [ -n "$_shiten_session_start" ]; then',
  "    local _end=$(date +%s)",
  '    local _duration=$(( _end - _shiten_session_start ))',
  '    if [ "$_duration" -gt 5 ]; then',
  "      command -v shiten >/dev/null 2>&1 && shiten feedback --outcome session-end --duration \"$_duration\" 2>/dev/null &",
  "    fi",
  '    _shiten_session_start=""',
  "  fi",
  "}",
  "",
  "# Zsh hooks",
  'if [ -n "$ZSH_VERSION" ]; then',
  "  autoload -Uz add-zsh-hook 2>/dev/null",
  "  add-zsh-hook preexec _shiten_hook_preexec 2>/dev/null",
  "  add-zsh-hook precmd _shiten_hook_precmd 2>/dev/null",
  "# Bash hooks",
  'elif [ -n "$BASH_VERSION" ]; then',
  "  _shiten_preexec() {",
  "    _shiten_hook_preexec",
  "  }",
  "  _shiten_prompt_command() {",
  "    _shiten_hook_precmd",
  "  }",
  "  trap '_shiten_preexec' DEBUG 2>/dev/null",
  '  PROMPT_COMMAND="_shiten_prompt_command;${PROMPT_COMMAND:-}"',
  "fi",
  "",
  "# ── End Shiten Shell Integration ──────────────────────────────────────────────",
].join("\n");

// ── Command ──────────────────────────────────────────────────────────────────

export const shellInitCommand = new Command("shell-init")
  .description("Output shell hooks for session tracking (add eval to .bashrc/.zshrc)")
  .action(() => {
    process.stdout.write(SHELL_SCRIPT + "\n");
  });
